// config.mjs
import { readFile } from "fs/promises";
import { fileURLToPath } from "url";
import { dirname, join } from "path";

const __dirname = dirname(fileURLToPath(import.meta.url));

// Top-level await: no async wrapper needed!
const config = JSON.parse(
  await readFile(join(__dirname, "config.json"), "utf8")
);

export default config;

// app.mjs
import config from "./config.mjs";

// config is already loaded before this runs
console.log("Server port:", config.port);
console.log("Database:", config.database.host);

// Multiple top-level awaits run in order
const data1 = await fetch("https://api.example.com/data1");
const data2 = await fetch("https://api.example.com/data2");

// Parallel top-level awaits:
const [a, b] = await Promise.all([
  fetch("https://api.example.com/a"),
  fetch("https://api.example.com/b")
]);

export { data1, data2, a, b };

// live.mjs
export let value = 1;

export function increment() {
  value++;
}

export function setValue(v) {
  value = v;
}

// In the same module, schedule an update
setTimeout(function() {
  value = 100;
}, 100);

// importer.mjs
import { value, increment, setValue } from "./live.mjs";

console.log("Initial:", value); // 1

increment();
console.log("After increment:", value); // 2 (live!)

setValue(42);
console.log("After setValue:", value); // 42

// Wait for the setTimeout to fire
setTimeout(function() {
  console.log("After module timeout:", value); // 100
}, 200);

// Compare with CJS:
// In CJS, module.exports copies the value, so
// changes to module-level variables after export are NOT reflected.
// ESM live bindings always reflect the current value.

// esm-app.mjs
import { createRequire } from "module";
import { fileURLToPath } from "url";
import { dirname } from "path";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

// Create a CJS require function in ESM
const require = createRequire(import.meta.url);

// Now we can require CJS modules
const fs = require("fs");
const lodash = require("lodash");
const pkg = require("./package.json");

console.log("App name:", pkg.name);
console.log("Lodash version:", lodash.VERSION);

// Also use proper ESM imports for ESM packages
import { readFile } from "fs/promises";

// Dynamic import() for ESM modules from CJS-compatible code
async function loadESM() {
  const chalk = await import("chalk");
  console.log(chalk.default.green("ESM module loaded!"));
}

loadESM();

// Export both ESM and CJS compatible
export const greeting = "Hello from ESM";

// Also set module.exports for CJS require()
module.exports = { greeting }; // This works via createRequire
